/**
 * @file fft_radix2_avx512.h
 * @brief DFT-2 AVX512 codelets
 *
 * t2 codelets: loop over K, elements at stride K
 *   notw/tw_dit/tw_dif (K parameter = stride = loop bound)
 * sv codelets: no loop, elements at stride vs (SIMD-width)
 *   n1sv/t1sv_dit/t1sv_dif (vs parameter = element stride)
 *   Executor calls K/VL times, advancing pointers by VL=8.
 * CT codelets: n1 (stride is/os), t1_dit, t1_dif, n1_ovs
 *
 * Generated by gen_radix2.py
 */

