#ifndef R2Z_LD
#define R2Z_LD(p) _mm512_loadu_pd(p)
#endif
#ifndef R2Z_ST
#define R2Z_ST(p,v) _mm512_storeu_pd((p),(v))
#endif
#define LD R2Z_LD
#define ST R2Z_ST

